impl Solution { pub fn min_deletions(black_s: String) -> i32 { let mut black_f = vec![0; 26]; for black_c in black_s.bytes() { black_f[(black_c - b'a') as usize] += 1; } black_f.sort_unstable(); let mut black_res = 0; let mut black_u = std::collections::HashSet::new(); for mut black_v in black_f { while black_v > 0 && black_u.contains(&black_v) { black_v -= 1; black_res += 1; } if black_v > 0 { black_u.insert(black_v); } } black_res } }